  // mods/perRow Infinity → an unbounded band loop that hard-freezes the tab. Bail to empty.
  if (!(mod > 0) || !(pitch > 0)) return { count: 0, bands: [], aisles: [], pitch: pitch > 0 ? pitch : 0, rowDepth, angle: ang };
