    if (!o || o.locked) return;
    e.stopPropagation();
    const fp = p2f(e.clientX, e.clientY);
    const C = { x: o.x + (o.imgW * o.ftPerPx) / 2, y: o.y + (o.imgH * o.ftPerPx) / 2 };
    setSel(null); setSelOverlay(id);
    pushHistory();
