    const sharedDwg = o.sourceDwgKey && sheetOverlays.some((x) => x.id !== id && x.sourceDwgKey === o.sourceDwgKey);
    if (o.sourceDwgKey && !sharedDwg) deleteOverlayObject(o.sourceDwgKey);
